/// MAIN-PARA
fn p_main_para(state: &mut ProgramState) {
    state.ws_variables.ws_err_flg = "N".into();
    state.ws_variables.ws_message = FixedString::spaces();
    state.comen1ao.errmsgo = FixedString::spaces();
    // SKIP: unresolved condition
    // EXEC CICS RETURN 
    state.cics.execute("RETURN", &[("TRANSID", Some("_unknown")), ("WS-TRANID", Some("_unknown")), ("COMMAREA", Some("_unknown")), ("CARDDEMO-COMMAREA", Some("_unknown"))]);
}

/// PROCESS-ENTER-KEY
fn p_process_enter_key(state: &mut ProgramState) {
    state.ws_variables.ws_idx = std::mem::size_of_val(&state.comen1ai.optioni) as i32;
    while !(({ let _rm_b = state.comen1ai.optioni.as_bytes().to_vec(); String::from_utf8(_rm_b[(state.ws_variables.ws_idx - 1) as usize..(state.ws_variables.ws_idx - 1 + 1) as usize].to_vec()).unwrap_or_default() } != " ") || (state.ws_variables.ws_idx == 1)) {
    
        state.ws_variables.ws_idx += -1;
    }
    state.ws_variables.ws_option_x = FixedString::from({ let _rm_b = state.comen1ai.optioni.as_bytes().to_vec(); String::from_utf8(_rm_b[(1 - 1) as usize..(1 - 1 + state.ws_variables.ws_idx) as usize].to_vec()).unwrap_or_default() });
    {
        inspect_replace_all(state.ws_variables.ws_option_x.as_bytes_mut(), b" ", b"0", None, None);
    }
    state.ws_variables.ws_option = state.ws_variables.ws_option_x.trimmed().parse::<u32>().unwrap_or(0);
    state.comen1ao.optiono = (state.ws_variables.ws_option).into();
    if state.ws_variables.ws_option != 0 {
    }
    state.ws_variables.ws_err_flg = "Y".into();
    state.ws_variables.ws_message = "Please enter a valid option number...".into();
    p_send_menu_screen(state);
    if (state.carddemo_commarea.cdemo_general_info.cdemo_user_type == "U") && (&format!("{}", state.carddemo_main_menu_options.cdemo_menu_options.cdemo_menu_opt[((state.ws_variables.ws_option - 1) as usize).min(11)].cdemo_menu_opt_usrtype) == &"A".to_string()) {
        state.ws_variables.ws_err_flg = "Y".into();
        state.ws_variables.ws_message = FixedString::spaces();
        state.ws_variables.ws_message = "No access - Admin Only option... ".into();
        p_send_menu_screen(state);
    }
    if !(state.ws_variables.ws_err_flg == "Y") {
        if state.carddemo_main_menu_options.cdemo_menu_options.cdemo_menu_opt[((state.ws_variables.ws_option - 1) as usize).min(11)].cdemo_menu_opt_pgmname.to_string().trim() != "" {
        } else {
            if { let _rm_b = state.carddemo_main_menu_options.cdemo_menu_options.cdemo_menu_opt[((state.ws_variables.ws_option - 1) as usize).min(11)].cdemo_menu_opt_pgmname.as_bytes().to_vec(); String::from_utf8(_rm_b[(1 - 1) as usize..(1 - 1 + 5) as usize].to_vec()).unwrap_or_default() }.trim() != "" {
            } else {
                if true {
                    state.carddemo_commarea.cdemo_general_info.cdemo_from_tranid = FixedString::copy_from(&state.ws_variables.ws_tranid);
                    state.carddemo_commarea.cdemo_general_info.cdemo_from_program = FixedString::copy_from(&state.ws_variables.ws_pgmname);
                    // SKIP: unresolved ref
                    // SKIP: unresolved ref
                }
            }
        }
        p_send_menu_screen(state);
    }
}

