/// POPULATE-HEADER-INFO
fn p_populate_header_info(state: &mut ProgramState) {
    {
        let _bytes = b"20260319120000+0000";
        let _len = _bytes.len();
        if _len > 0 { let _end = _len.min(0+4); let _s = String::from_utf8_lossy(&_bytes[0.._end]).trim().to_string(); state.ws_date_time.ws_curdate_data.ws_curdate.ws_curdate_year = _s.parse().unwrap_or_default(); }
        if _len > 4 { let _end = _len.min(4+2); let _s = String::from_utf8_lossy(&_bytes[4.._end]).trim().to_string(); state.ws_date_time.ws_curdate_data.ws_curdate.ws_curdate_month = _s.parse().unwrap_or_default(); }
        if _len > 6 { let _end = _len.min(6+2); let _s = String::from_utf8_lossy(&_bytes[6.._end]).trim().to_string(); state.ws_date_time.ws_curdate_data.ws_curdate.ws_curdate_day = _s.parse().unwrap_or_default(); }
        if _len > 0 { let _end = _len.min(0+8); let _s = String::from_utf8_lossy(&_bytes[0.._end]).trim().to_string(); state.ws_date_time.ws_curdate_data.ws_curdate_n = _s.parse().unwrap_or_default(); }
        if _len > 8 { let _end = _len.min(8+2); let _s = String::from_utf8_lossy(&_bytes[8.._end]).trim().to_string(); state.ws_date_time.ws_curdate_data.ws_curtime.ws_curtime_hours = _s.parse().unwrap_or_default(); }
        if _len > 10 { let _end = _len.min(10+2); let _s = String::from_utf8_lossy(&_bytes[10.._end]).trim().to_string(); state.ws_date_time.ws_curdate_data.ws_curtime.ws_curtime_minute = _s.parse().unwrap_or_default(); }
        if _len > 12 { let _end = _len.min(12+2); let _s = String::from_utf8_lossy(&_bytes[12.._end]).trim().to_string(); state.ws_date_time.ws_curdate_data.ws_curtime.ws_curtime_second = _s.parse().unwrap_or_default(); }
        if _len > 14 { let _end = _len.min(14+2); let _s = String::from_utf8_lossy(&_bytes[14.._end]).trim().to_string(); state.ws_date_time.ws_curdate_data.ws_curtime.ws_curtime_milsec = _s.parse().unwrap_or_default(); }
        if _len > 8 { let _end = _len.min(8+8); let _s = String::from_utf8_lossy(&_bytes[8.._end]).trim().to_string(); state.ws_date_time.ws_curdate_data.ws_curtime_n = _s.parse().unwrap_or_default(); }
    }
    state.comen1ao.title01o = FixedString::copy_from(&state.ccda_screen_title.ccda_title01);
    state.comen1ao.title02o = FixedString::copy_from(&state.ccda_screen_title.ccda_title02);
    state.comen1ao.trnnameo = FixedString::copy_from(&state.ws_variables.ws_tranid);
    state.comen1ao.pgmnameo = FixedString::copy_from(&state.ws_variables.ws_pgmname);
    state.ws_date_time.ws_curdate_mm_dd_yy.ws_curdate_mm = state.ws_date_time.ws_curdate_data.ws_curdate.ws_curdate_month as u32;
    state.ws_date_time.ws_curdate_mm_dd_yy.ws_curdate_dd = state.ws_date_time.ws_curdate_data.ws_curdate.ws_curdate_day as u32;
    state.ws_date_time.ws_curdate_mm_dd_yy.ws_curdate_yy = { let _rm_s = state.ws_date_time.ws_curdate_data.ws_curdate.ws_curdate_year.to_string(); String::from(&_rm_s[(3 - 1) as usize..(3 - 1 + 2) as usize]) }.trim().parse::<u32>().unwrap_or(0);
    state.comen1ao.curdateo = FixedString::copy_from(&state.ws_date_time.ws_curdate_mm_dd_yy);
    state.ws_date_time.ws_curtime_hh_mm_ss.ws_curtime_hh = state.ws_date_time.ws_curdate_data.ws_curtime.ws_curtime_hours as u32;
    state.ws_date_time.ws_curtime_hh_mm_ss.ws_curtime_mm = state.ws_date_time.ws_curdate_data.ws_curtime.ws_curtime_minute as u32;
    state.ws_date_time.ws_curtime_hh_mm_ss.ws_curtime_ss = state.ws_date_time.ws_curdate_data.ws_curtime.ws_curtime_second as u32;
    state.comen1ao.curtimeo = FixedString::copy_from(&state.ws_date_time.ws_curtime_hh_mm_ss);
}

/// BUILD-MENU-OPTIONS
fn p_build_menu_options(state: &mut ProgramState) {
    state.ws_variables.ws_idx = 1;
    while !((state.ws_variables.ws_idx as i64) > (state.carddemo_main_menu_options.cdemo_menu_opt_count as i64)) {
        state.ws_variables.ws_menu_opt_txt = FixedString::spaces();
        {
        let mut _str_ptr: usize = 1;
        { let _bytes_tmp = state.carddemo_main_menu_options.cdemo_menu_options.cdemo_menu_opt[((state.ws_variables.ws_idx - 1) as usize).min(11)].cdemo_menu_opt_num.to_string();
        string_append(state.ws_variables.ws_menu_opt_txt.as_bytes_mut(), &mut _str_ptr, _bytes_tmp.as_bytes()); }
        string_append(state.ws_variables.ws_menu_opt_txt.as_bytes_mut(), &mut _str_ptr, ". ".as_bytes());
        { let _bytes_tmp = state.carddemo_main_menu_options.cdemo_menu_options.cdemo_menu_opt[((state.ws_variables.ws_idx - 1) as usize).min(11)].cdemo_menu_opt_name.to_string();
        string_append(state.ws_variables.ws_menu_opt_txt.as_bytes_mut(), &mut _str_ptr, _bytes_tmp.as_bytes()); }
    }
        /* TODO: complex stmt */
        state.ws_variables.ws_idx += 1;
    }
}

